// Converts simple markdown (## / ### headings, blank-line paragraphs, '- ' bullets) into
// Sanity Portable Text blocks matching the shape used by article.body.
const md = $('Parse Article').item.json.article.bodyMarkdown;
const lines = md.split('\n');
const blocks = [];
function key() { return Math.random().toString(36).slice(2, 10); }
function textSpan(text) { return [{ _type: 'span', _key: key(), text, marks: [] }]; }

let bulletBuffer = [];
function flushBullets() {
  for (const b of bulletBuffer) {
    blocks.push({ _type: 'block', _key: key(), style: 'normal', listItem: 'bullet', level: 1, children: textSpan(b) });
  }
  bulletBuffer = [];
}

for (const rawLine of lines) {
  const line = rawLine.trim();
  if (!line) { flushBullets(); continue; }
  if (line.startsWith('### ')) { flushBullets(); blocks.push({ _type: 'block', _key: key(), style: 'h3', children: textSpan(line.slice(4)) }); continue; }
  if (line.startsWith('## ')) { flushBullets(); blocks.push({ _type: 'block', _key: key(), style: 'h2', children: textSpan(line.slice(3)) }); continue; }
  if (line.startsWith('- ') || line.startsWith('* ')) { bulletBuffer.push(line.slice(2)); continue; }
  flushBullets();
  blocks.push({ _type: 'block', _key: key(), style: 'normal', children: textSpan(line) });
}
flushBullets();

function slugify(s) {
  return s.toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').slice(0, 90);
}

return [{ json: { bodyBlocks: blocks, slug: slugify($('Parse Article').item.json.article.title) } }];

const imgB64 = $('Image Agent').item.json.data[0].b64_json;
const buffer = Buffer.from(imgB64, 'base64');
return [{
  json: {},
  binary: { image: { data: imgB64, mimeType: 'image/png', fileName: 'cover.png' } }
}];

